    const N = grid[0].length;

    // DP[i][j] will store a Set of all possible XOR sums reaching cell (i, j)
    // Initialize DP table: M rows, N columns, each element is a Set
    const DP = Array(M).fill(0).map(() => Array(N).fill(null));

