        const g_ij = grid[0][j];
        for (const xorSum of DP[0][j - 1]) {
            DP[0][j].add(xorSum ^ g_ij);
        }
    }

    // Fill first column (j=0, i > 0)
    for (let i = 1; i < M; i++) {
        const g_ij = grid[i][0];
        for (const xorSum of DP[i - 1][0]) {
            DP[i][0].add(xorSum ^ g_ij);
        }
    }

    // Fill the rest of the grid
    for (let i = 1; i < M; i++) {
        for (let j = 1; j < N; j++) {
            const g_ij = grid[i][j];

            // From top (i-1, j)
            for (const xorSum of DP[i - 1][j]) {
                DP[i][j].add(xorSum ^ g_ij);
            }

            // From left (i, j-1)
            for (const xorSum of DP[i][j - 1]) {
                DP[i][j].add(xorSum ^ g_ij);
            }
        }
    }

    // Find the minimum XOR sum at the target cell (M-1, N-1)
    const finalSet = DP[M - 1][N - 1];

    if (finalSet.size === 0) {
        // This case should not happen based on constraints M, N >= 1
        return 0; 
    }

    let minXor = 1024; // Max possible value is 1023
    for (const xorSum of finalSet) {
        if (xorSum < minXor) {
            minXor = xorSum;
        }
    }

    return minXor;
}

