import scala.collection.mutable

object Solution {
  def grid(grid: Array[Array[Long]]): Long = {
    val M = grid.length
    val N = grid(0).length

    // Initialize DP table: Array[Array[Set[Long]]]
    // We use mutable HashSets temporarily during calculation for efficiency
    val dp = Array.ofDim[Array[mutable.HashSet[Long]]](M)
    for (i <- 0 until M) {
      dp(i) = Array.ofDim[mutable.HashSet[Long]](N)
    }

    // Base Case: (0, 0)
    dp(0)(0) = mutable.HashSet(grid(0)(0))

    // Fill the rest of the grid
    for (i <- 0 until M) {
      for (j <- 0 until N) {
        if (i == 0 && j == 0) continue

        val g_ij = grid(i)(j)
        val currentSet = mutable.HashSet[Long]()

        // From top (i-1, j)
        if (i > 0) {
          for (xorSum <- dp(i - 1)(j)) {
            currentSet.add(xorSum ^ g_ij)
          }
        }

        // From left (i, j-1)
        if (j > 0) {
          for (xorSum <- dp(i)(j - 1)) {
            currentSet.add(xorSum ^ g_ij)
          }
        }

        dp(i)(j) = currentSet
      }
    }

    // Find the minimum XOR sum at the target cell (M-1, N-1)
    val finalSet = dp(M - 1)(N - 1)

    // Since M*N >= 1, the set is guaranteed not to be empty.
    finalSet.min
  }
}

