function solve(grid) {
    const M = grid.length;
    const N = grid[0].length;

    // DP[i][j] will store a Set of all possible XOR sums reaching cell (i, j)
    // Initialize DP table: M rows, N columns, each element is a Set
    const DP = Array(M).fill(0).map(() => Array(N).fill(null));

    for (let i = 0; i < M; i++) {
        for (let j = 0; j < N; j++) {
            DP[i][j] = new Set();
        }
    }

    // Base Case: (0, 0)
    DP[0][0].add(grid[0][0]);

    // Fill first row (i=0, j > 0)
    for (let j = 1; j < N; j++) {
        const g_ij = grid[0][j];
        for (const xorSum of DP[0][j - 1]) {
            DP[0][j].add(xorSum ^ g_ij);
        }
