            for (const xorSum of DP[i - 1][j]) {
                DP[i][j].add(xorSum ^ g_ij);
            }

            // From left (i, j-1)
            for (const xorSum of DP[i][j - 1]) {
                DP[i][j].add(xorSum ^ g_ij);
            }
        }
    }

    // Find the minimum XOR sum at the target cell (M-1, N-1)
    const finalSet = DP[M - 1][N - 1];

